import{_ as e,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const f=JSON.parse('{"title":"写入流程与近实时搜索","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/11-ElasticSearch学习/04-写入流程与近实时搜索.md","filePath":"语言/java/11-ElasticSearch学习/04-写入流程与近实时搜索.md","lastUpdated":1776149370000}'),h={name:"语言/java/11-ElasticSearch学习/04-写入流程与近实时搜索.md"};function t(s,a,_,n,d,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="写入流程与近实时搜索" tabindex="-1">写入流程与近实时搜索 <a class="header-anchor" href="#写入流程与近实时搜索" aria-label="Permalink to “写入流程与近实时搜索”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>ES 的写入不是立刻就能被搜索到，而是经过刷新和段合并等过程进入可检索状态。<br> 这就是它“近实时搜索”特性的来源。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>如果不了解写入链路，就很难解释为什么数据刚写入时搜索不到，或者为什么频繁刷新会影响性能。<br> 这是业务预期和性能治理中的高频问题。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>写入 buffer</li><li>refresh</li><li>flush</li><li>segment</li><li>merge</li><li>近实时搜索机制</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解写入和可搜索不是同一时刻</li><li>理解 refresh 会影响写入吞吐</li><li>理解 segment 合并和资源消耗的关系</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>误以为写成功就一定能立刻搜到</li><li>频繁主动 refresh 导致性能抖动</li><li>忽略写入和查询的权衡</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>画一张 ES 写入到可搜索的流程图</li><li>观察 refresh 间隔变化带来的影响</li><li>总结写入和搜索一致性的业务处理方式</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>为什么 ES 是近实时而不是强实时</li><li>refresh 和 flush 分别在做什么</li><li>为什么频繁 refresh 会影响性能</li></ul>',15)])])}const m=e(h,[["render",t]]);export{f as __pageData,m as default};
